"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useEffect, useMemo, useState } from "react";
import { ChevronDown, Home } from "lucide-react";
import { loadTemplateFromStorage, type TemplateType } from "@/lib/storage-utils";

export function Header() {
  const pathname = usePathname();
  const isHome = pathname === "/";
  const isEditor = pathname === "/editor";

  const templates = useMemo(() => ["a", "b", "c", "d"] as const, []);
  const [templateOpen, setTemplateOpen] = useState(false);
  const [currentTemplate, setCurrentTemplate] = useState<TemplateType>("a");

  useEffect(() => {
    const t = loadTemplateFromStorage();
    if (t) setCurrentTemplate(t);
  }, [pathname]);

  useEffect(() => {
    if (!templateOpen) return;
    const onMouseDown = (e: MouseEvent) => {
      const el = e.target as HTMLElement | null;
      if (!el) return;
      if (el.closest("[data-template-gnb]")) return;
      setTemplateOpen(false);
    };
    window.addEventListener("mousedown", onMouseDown);
    return () => window.removeEventListener("mousedown", onMouseDown);
  }, [templateOpen]);

  if (isHome) {
    return null;
  }

  return (
    <header className="border-b border-gray-200 bg-white">
      <div className="mx-auto flex max-w-6xl items-center justify-between gap-4 px-4 py-2">
        <div className="flex items-center gap-2">
          <Link
            href="/"
            aria-label="홈"
            className="inline-flex h-10 w-10 items-center justify-center rounded-xl text-gray-800 transition-colors hover:bg-gray-100"
          >
            <Home className="size-5" />
          </Link>
        </div>

        {isEditor ? (
          <nav className="flex flex-wrap items-center justify-end gap-2">
            <button
              type="button"
              onClick={() => document.getElementById("editor-reset-btn")?.click()}
              className="inline-flex items-center rounded-full bg-white px-4 py-2 text-sm font-semibold text-gray-800 shadow-sm ring-1 ring-gray-200 transition-colors hover:bg-gray-50"
            >
              새로 만들기
            </button>

            <button
              type="button"
              onClick={() => document.getElementById("editor-import-file")?.click()}
              className="inline-flex items-center rounded-full bg-white px-4 py-2 text-sm font-semibold text-gray-800 shadow-sm ring-1 ring-gray-200 transition-colors hover:bg-gray-50"
            >
              불러오기
            </button>

            <div className="relative" data-template-gnb>
              <button
                type="button"
                onClick={() => setTemplateOpen((v) => !v)}
                className="inline-flex items-center rounded-full bg-white px-4 py-2 text-sm font-semibold text-gray-800 shadow-sm ring-1 ring-gray-200 transition-colors hover:bg-gray-50"
              >
                템플릿
                <ChevronDown className="ml-1 size-4 text-gray-500" />
              </button>

              {templateOpen && (
                <div className="absolute right-0 z-[100] mt-2 w-56 overflow-hidden rounded-2xl border border-gray-200 bg-white shadow-[0_10px_40px_rgba(0,0,0,0.12)]">
                  <div className="px-3 py-2 text-xs font-semibold text-gray-500">
                    현재: {currentTemplate.toUpperCase()}
                  </div>
                  <div className="flex flex-col p-2">
                    {templates.map((t) => (
                      <button
                        key={t}
                        type="button"
                        onClick={() => {
                          setTemplateOpen(false);
                          setCurrentTemplate(t);
                          document
                            .getElementById(`editor-set-template-${t}`)
                            ?.click();
                        }}
                        className={`rounded-xl px-3 py-2 text-left text-sm font-semibold transition-colors ${
                          t === currentTemplate
                            ? "bg-[#6a5acd]/10 text-[#6a5acd]"
                            : "bg-transparent text-gray-800 hover:bg-gray-50"
                        }`}
                      >
                        템플릿 {t.toUpperCase()}
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <button
              type="button"
              onClick={() => document.getElementById("editor-save-btn")?.click()}
              className="inline-flex items-center rounded-full bg-[#6a5acd] px-4 py-2 text-sm font-semibold text-white shadow-sm transition-colors hover:bg-[#5a4abd]"
            >
              저장
            </button>

            <Link
              href="/view/preview"
              target="_blank"
              rel="noopener noreferrer"
              className="inline-flex items-center rounded-full bg-white px-4 py-2 text-sm font-semibold text-gray-800 shadow-sm ring-1 ring-gray-200 transition-colors hover:bg-gray-50"
            >
              미리보기
            </Link>
          </nav>
        ) : (
          <div className="h-10" />
        )}
      </div>
    </header>
  );
}
